// Maximum tier for array sizing and iteration counts
const MAX_TIER = Tier.DIAMOND;

// DH parameters (small for demonstration, should be large primes in production)
const DH_PRIME = BigInt(''); // 2048-bit prime
const DH_GENERATOR = 2n;

