    const multipliers = [1.0, 1.1, 1.25, 1.5, 2.0, 3.0, 5.0];

    // Determine tier with constant-time operations
    let tier = 0;
    for (let i = 0; i < thresholds.length; i++) {
      const shouldAdvance = constantTimeGTE(activity, thresholds[i]);
      tier = tier + (shouldAdvance ? 1 : 0);
    }

