      tierBonus,
      activityBonus,
      timeBonus,
      dhProof: bytesToHex(this.bigIntToBytes(dhProofValue, 32)),
      rsaSignature: bytesToHex(this.bigIntToBytes(rsaSignatureValue, 32)),
