// Utility functions for hex conversion
function bytesToHex(bytes: Uint8Array): string {
  return Array.from(bytes)
    .map(b => b.toString(16).padStart(2, '0'))
    .join('');
}

function hexToBytes(hex: string): Uint8Array {
  if (hex.length % 2 !== 0) {
    throw new Error('Hex string must have even length');
  }
  const bytes = new Uint8Array(hex.length / 2);
  for (let i = 0; i < hex.length; i += 2) {
    bytes[i / 2] = parseInt(hex.substring(i, i + 2), 16);
  }
  return bytes;
}

/**
 * Compare two values in constant time
 * Returns 1 if a >= b, 0 otherwise
 */
function constantTimeGTE(a: number, b: number): number {
  // Constant time comparison using bit operations
  // Returns 1 if a >= b, 0 otherwise
  const diff = a - b;
  // Extract sign bit: if negative, bit 31 is 1
  return ((diff >> 31) & 1) === 0 ? 1 : 0;
}

/**
 * Modular exponentiation optimized for constant time
 * Uses fixed iteration count regardless of exponent size
 */
function constantTimeModPow(base: bigint, exponent: bigint, modulus: bigint): bigint {
  // Montgomery ladder for constant-time exponentiation
  let result = 1n;
  let basePow = base % modulus;

  // Convert exponent to fixed-size bits
  const maxBits = 256; // Use fixed 256-bit exponent

  for (let i = maxBits - 1; i >= 0; i--) {
    const bit = (exponent >> BigInt(i)) & 1n;

    // Square step (always performed)
    const tempBase = (basePow * basePow) % modulus;

    // Multiply step (conditionally, using constant-time selection)
    const tempResult = bit === 1n ? (result * basePow) % modulus : result;

    // Select results based on bit
    result = tempResult;
    basePow = tempBase;

    // Always do both operations (simulated with dummy operations)
    // In real constant-time code, we'd do:
    // t1 = (r * b) % mod  
    // t2 = r
    // r = bit ? t1 : t2
    // This ensures same execution path regardless of bit value
    const _dummy = ((result * 1n) % modulus) * 0n;
    void _dummy; // Prevent optimization
  }

  return result;
}

/**
 * Calculate DH shared secret in constant time
 */
function calculateDHConstantTime(privateKey: bigint, publicKey: bigint): bigint {
  return constantTimeModPow(publicKey, privateKey, DH_PRIME);
}

/**
 * Calculate RSA signature in constant time
 * Uses padding and fixed-size operations
 */
function calculateRSAConstantTime(messageHash: bigint, privateKey: bigint, modulus: bigint): bigint {
  // PKCS#1 v1.5 padding simulation (simplified)
  const paddedMessage = (messageHash << 128n) | (0x1n << 120n) | 0xFFn;
  return constantTimeModPow(paddedMessage, privateKey, modulus);
}

