    const bonuses = [0, 100, 250, 500, 1000, 2000]; // Index 0 unused

    let tierBonus = 0;
    // Iterate through ALL tiers (constant-time loop)
    for (let i = Tier.BRONZE; i <= MAX_TIER; i++) {
      const isTargetTier = constantTimeGTE(i, tier) & constantTimeGTE(tier, i);
      const bonus = bonuses[i] ?? 0;

      // Accumulate: add bonus only if this is the target tier
      tierBonus = (tierBonus + (isTargetTier ? bonus : 0));
    }

    return tierBonus;
  }

  /**
   * Calculate activity multiplier in constant time
   */
  calculateActivityMultiplier(activity: number): number {
    // Fixed number of operations regardless of activity level
    // Use bit masks instead of comparisons
    const thresholds = [0, 10, 50, 100, 500, 1000];
    const multipliers = [1.0, 1.1, 1.25, 1.5, 2.0, 3.0, 5.0];

    // Determine tier with constant-time operations
    let tier = 0;
    for (let i = 0; i < thresholds.length; i++) {
      const shouldAdvance = constantTimeGTE(activity, thresholds[i]);
      tier = tier + (shouldAdvance ? 1 : 0);
    }

    // Clamp to valid range in constant time
    const clampedTier = tier < multipliers.length ? tier : multipliers.length - 1;
    return multipliers[clampedTier] ?? 1.0;
  }

